mapper.update:
UPDATE orders
SET
order_status = #{orderStatus}
WHERE id = #{id}

mapper.select:
SELECT id, member_id AS memberId, order_no AS orderNo, total_price AS totalPrice, delivery_fee AS deliveryFee, final_price AS finalPrice, order_name AS orderName, order_phone AS orderPhone, receiver_name AS receiverName, receiver_phone AS receiverPhone, address, delivery_message AS deliveryMessage, depositor_name AS depositorName, bank_info AS bankInfo, order_status AS orderStatus, payment_method AS paymentMethod, payment_status AS paymentStatus, toss_payment_key AS tossPaymentKey, delivery_company AS deliveryCompany, tracking_no AS trackingNo, created_at AS createdAt FROM orders WHERE 1=1
AND DATE(created_at) >= #{startDate}
AND DATE(created_at) <= #{endDate}
ORDER BY
id order_no order_name order_phone payment_method payment_status order_status final_price created_at id
ASC DESC

SELECT id, member_id AS memberId, order_no AS orderNo, total_price AS totalPrice, delivery_fee AS deliveryFee, final_price AS finalPrice, order_name AS orderName, order_phone AS orderPhone, receiver_name AS receiverName, receiver_phone AS receiverPhone, address, delivery_message AS deliveryMessage, depositor_name AS depositorName, bank_info AS bankInfo, order_status AS orderStatus, payment_method AS paymentMethod, payment_status AS paymentStatus, toss_payment_key AS tossPaymentKey, delivery_company AS deliveryCompany, tracking_no AS trackingNo, created_at AS createdAt FROM orders WHERE member_id = #{memberId}
AND DATE(created_at) >= #{startDate}
AND DATE(created_at) <= #{endDate}
ORDER BY id DESC
